#include <iostream>
using namespace std;

int max(int a, int b) {
  return (a > b) ? a : b;
}

double max(double a, double b) {
  return (a > b) ? a : b;
}

int main() {
  cout << max(5, 10) << endl;     // Calls int version
  cout << max(3.5, 2.1) << endl;  // Calls double version
  return 0;
}
